public class SrcCharToDestChar {
    public static int srcCharToDestChar(int ch) {
            int result = ch;
            if (ch >= '0' && ch <= '9') {
                result = (ch - '0') + 'A';
            } else if (ch >= 'a' && ch <= 'f') {
                result = (ch - 'a') + 10 + 'A';
            }
            return result;
        }
