public class Dmod {
    public static double dmod(double a, double b) {
            double c;
            if (b != 0.0) {
                if ((a * b) > 0.0) {
                    c = a - (b * Math.floor(a / b));
                } else {
                    c = a + (b * Math.floor(-a / b));
                }
            } else {
                c = a;
            }
            return c;
        }
