public class IsExtender {
    public static boolean isExtender(final char ch) {
            if ((ch >= 0x3031) && (ch <= 0x3035)) {
                return true;
            }
            if ((ch >= 0x30FC) && (ch <= 0x30FE)) {
                return true;
            }
            switch(ch) {
                case 0x00B7:
                case 0x02D0:
                case 0x02D1:
                case 0x0387:
                case 0x0640:
                case 0x0E46:
                case 0x0EC6:
                case 0x3005:
                case 0x309D:
                case 0x309E:
                    return true;
                default:
                    break;
            }
            return false;
        }
