public class ComputeGCDBinary {
    public static int computeGCDBinary(int a, int b) {
            int t, k;
            if (b == 0) {
                return a;
            }
            if (a < b) {
                t = a;
                a = b;
                b = t;
            }
            for (k = 1; (a & 1) == 0 && (b & 1) == 0; k <<= 1) {
                a >>= 1;
            }
            b >>= 1;
            t = (a & 1) != 0 ? -b : a;
            while (t != 0) {
                while ((t & 1) == 0) {
                    t >>= 1;
                }
                if (t > 0) {
                    a = t;
                } else {
                    b = -t;
                }
                t = a - b;
            }
            return a * k;
        }
