public class PrimeNumber {
    public static int primeNumber(int num) {
            if (num == 1) {
                return 1;
            }
            int[] primes = new int[(2 * num) + 1];
            for (int i = 2; i <= 2 * num; i++) {
                primes[i] = i;
            }
            for (int i = 2; i * i <= 2 * num; i++) {
                if (primes[i] != -1) {
                    for (int j = i; i * j <= 2 * num; j++) {
                        primes[j * i] = -1;
                    }
                }
            }
            int primeToReturn = 101;
            for (int i = num; i <= 2 * num; i++) {
                if (primes[i] != -1) {
                    primeToReturn = primes[i];
                    break;
                }
            }
            return primeToReturn;
        }
},8,25,11

public class GetPadBits {
    public static int getPadBits(int bitString) {
            int val = 0;
            for (int i = 3; i >= 0; i--) {
                //
                // this may look a little odd, but if it isn't done like this pre jdk1.2
                // JVM's break!
                //
                if (i != 0) {
                    if ((bitString >> (i * 8)) != 0) {
                        val = (bitString >> (i * 8)) & 0xFF;
                        break;
                    }
                } else {
                    if (bitString != 0) {
                        val = bitString & 0xFF;
                        break;
                    }
                }
            }
            if (val == 0) {
                return 7;
            }
            int bits = 1;
            while (((val <<= 1) & 0xFF) != 0) {
                bits++;
            }
            return 8 - bits;
        }
