public class GetCellState {
    public int getCellState(int cellState, int neighborCount) {
            if (cellState == 0) {
                if (neighborCount == 5)
                    return 1;
                return 0;
            } else if (cellState == 1) {
                if (neighborCount < 4)
                    return 0;
                if (neighborCount > 7)
                    return 0;
                if (neighborCount == 5)
                    return 2;
                return 1;
            } else {
                if (neighborCount < 4)
                    return 1;
                if (neighborCount > 7)
                    return 1;
                return 2;
            }
        }
