public class GetExactHWEPValue {
    public static double getExactHWEPValue(int obs_hets, int obs_hom1, int obs_hom2) {
            //System.out.println("Starting exact HWE:\t" + obs_hets + "\t" + obs_hom1 + "\t" + obs_hom2);
            int obs_homc = obs_hom1 < obs_hom2 ? obs_hom2 : obs_hom1;
            int obs_homr = obs_hom1 < obs_hom2 ? obs_hom1 : obs_hom2;
            int rare_copies = 2 * obs_homr + obs_hets;
            int genotypes = obs_hets + obs_homc + obs_homr;
            if (genotypes == 0)
                return -1;
            double[] het_probs = new double[rare_copies + 1];
            int i;
            for (i = 0; i <= rare_copies; i++) het_probs[i] = 0.0;
            /* start at midpoint */
            int mid = rare_copies * (2 * genotypes - rare_copies) / (2 * genotypes);
            /* check to ensure that midpoint and rare alleles have same parity */
            if (mid % 2 != rare_copies % 2)
                mid++;
            int curr_hets = mid;
            int curr_homr = (rare_copies - mid) / 2;
            int curr_homc = genotypes - curr_hets - curr_homr;
            het_probs[mid] = 1.0;
            double sum = het_probs[mid];
            for (curr_hets = mid; curr_hets > 1; curr_hets -= 2) {
                het_probs[curr_hets - 2] = het_probs[curr_hets] * curr_hets * (curr_hets - 1.0) / (4.0 * (curr_homr + 1.0) * (curr_homc + 1.0));
                sum += het_probs[curr_hets - 2];
                /* 2 fewer heterozygotes for next iteration -> add one rare, one common homozygote */
                curr_homr++;
                curr_homc++;
            }
            curr_hets = mid;
            curr_homr = (rare_copies - mid) / 2;
            curr_homc = genotypes - curr_hets - curr_homr;
            for (curr_hets = mid; curr_hets <= rare_copies - 2; curr_hets += 2) {
                het_probs[curr_hets + 2] = het_probs[curr_hets] * 4.0 * curr_homr * curr_homc / ((curr_hets + 2.0) * (curr_hets + 1.0));
                sum += het_probs[curr_hets + 2];
                curr_homr--;
                curr_homc--;
            }
            for (i = 0; i <= rare_copies; i++) het_probs[i] /= sum;
            double p_hwe = 0.0;
            for (i = 0; i <= rare_copies; i++) {
                if (het_probs[i] <= het_probs[obs_hets]) {
                    p_hwe += het_probs[i];
                }
            }
            p_hwe = p_hwe > 1.0 ? 1.0 : p_hwe;
            return p_hwe;
        }
