public class IsPunctuation {
    public static boolean isPunctuation(int c) {
            if ((c >= 0x0021) && (c <= 0x002F)) {
                // basic latin punctuation
                return true;
            } else if ((c >= 0x003A) && (c <= 0x0040)) {
                // basic latin punctuation
                return true;
            } else if ((c >= 0x005F) && (c <= 0x0060)) {
                // basic latin punctuation
                return true;
            } else if ((c >= 0x007E) && (c <= 0x007E)) {
                // basic latin punctuation
                return true;
            } else if ((c >= 0x007E) && (c <= 0x007E)) {
                // basic latin punctuation
                return true;
            } else if ((c >= 0x00A1) && (c <= 0x00BF)) {
                // latin supplement punctuation
                return true;
            } else if ((c >= 0x00D7) && (c <= 0x00D7)) {
                // latin supplement punctuation
                return true;
            } else if ((c >= 0x00F7) && (c <= 0x00F7)) {
                // latin supplement punctuation
                return true;
            } else if ((c >= 0x2000) && (c <= 0x206F)) {
                // general punctuation
                return true;
            } else {
                // [TBD] - not complete
                return false;
            }
        }
