public class Collides {
    public static boolean collides(int ax, int ay, int aw, int ah, int bx, int by, int bw, int bh) {
            boolean incol = false;
            boolean inrow = false;
            if (ax >= bx && ax <= bx + bw)
                incol = true;
            if (ax + aw >= bx && ax + aw <= bx + bw)
                incol = true;
            if (ay >= by && ay <= by + bh)
                inrow = true;
            if (ay + ah >= by && ay + ah <= by + bh)
                inrow = true;
            if (bx >= ax && bx <= ax + aw)
                incol = true;
            if (bx + bw >= ax && bx + bw <= ax + aw)
                incol = true;
            if (by >= ay && by <= ay + ah)
                inrow = true;
            if (by + bh >= ay && by + bh <= ay + ah)
                inrow = true;
            if (inrow && incol)
                return true;
            return false;
        }
