public class DpApproach {
    public static int dpApproach(int n, int r) {
            if (r > n)
                return -1;
            if (n == r)
                return 1;
            if (r == 0)
                return n;
            int[][] dp = new int[n + 1][r + 1];
            for (int i = 1; i <= n; i++) {
                for (int j = 0; j <= r; j++) {
                    if (i >= j) {
                        if (j == 0) {
                            dp[i][j] = i;
                        } else if (i == j) {
                            dp[i][j] = 1;
                        } else if (j == 1) {
                            dp[i][j] = i;
                        } else {
                            dp[i][j] = (dp[i - 1][j] + dp[i - 1][j - 1]) % 1000000007;
                        }
                    }
                }
            }
            //		print(dp);
            return dp[n][r];
        }
