public class Solve_quadratic {
    public static double solve_quadratic(double a, double b, double c) {
            double s1 = (-b + Math.sqrt(b * b - 4 * a * c)) / (2 * a);
            double s2 = (-b - Math.sqrt(b * b - 4 * a * c)) / (2 * a);
            if (s1 > .0 && s1 <= 1.0 && s2 > .0 && s2 <= 1.0) {
                if (s1 < s2)
                    return s1 + 1e-30;
                else
                    return s2 + 1e-30;
            }
            if (s1 > .0 && s1 <= 1.0)
                return s1;
            if (s2 > .0 && s2 <= 1.0)
                return s2;
            // TODO
            if (Math.abs(s1 - .0) < 1e-30)
                return 1e-30;
            if (Math.abs(s1 - 1.0) < 1e-30)
                return 1 - 1e-30;
            if (Math.abs(s2 - .0) < 1e-30)
                return 1e-30;
            if (Math.abs(s2 - 1.0) < 1e-30)
                return 1 - 1e-30;
            return s1;
        }
