public class CompareByArity {
    public static int compareByArity(int leftArityMismatch, int rightArityMismatch) {
            if (leftArityMismatch != rightArityMismatch) {
                if (leftArityMismatch == 0)
                    return -1;
                if (rightArityMismatch == 0)
                    return 1;
                if (Math.abs(leftArityMismatch) < Math.abs(rightArityMismatch))
                    return -1;
                if (Math.abs(leftArityMismatch) > Math.abs(rightArityMismatch))
                    return 1;
                if (leftArityMismatch > 0)
                    return -1;
                if (rightArityMismatch > 0)
                    return 1;
            }
            if (Math.abs(leftArityMismatch) < Math.abs(rightArityMismatch))
                return -1;
            if (Math.abs(leftArityMismatch) > Math.abs(rightArityMismatch))
                return 1;
            if (leftArityMismatch > 0)
                return -1;
            if (rightArityMismatch > 0)
                return 1;
            return 0;
        }
