public class Scale {
    public static int scale(double mmin, double mmax) {
            int fac = 0;
            double big = 0.0D;
            boolean test = false;
            if (mmin >= 0.0 && mmax > 0.0) {
                big = mmax;
                test = true;
            } else {
                if (mmin < 0.0 && mmax <= 0.0) {
                    big = -mmin;
                    test = true;
                } else {
                    if (mmax > 0.0 && mmin < 0.0) {
                        big = Math.max(mmax, -mmin);
                        test = true;
                    }
                }
            }
            if (test) {
                if (big > 100.0) {
                    while (big > 1.0) {
                        big /= 10.0;
                        fac--;
                    }
                }
                if (big <= 0.01) {
                    while (big <= 0.10) {
                        big *= 10.0;
                        fac++;
                    }
                }
            }
            return fac;
        }
