public class ToLowerCase {
    public static char toLowerCase(char letter) {
            // First deal with lower case, not accented letters
            if (letter >= 'α' && letter <= 'ω') {
                // Special case 'small final sigma', where we return 'small sigma'
                if (letter == 'ς') {
                    return 'σ';
                } else {
                    return letter;
                }
            }
            if (letter == 'ά') {
                return 'α';
            }
            // epsilon with acute
            if (letter == 'έ') {
                return 'ε';
            }
            // eta with acute
            if (letter == 'ή') {
                return 'η';
            }
            // iota with acute, iota with diaeresis, iota with acute and diaeresis
            if (letter == 'ί' || letter == 'ϊ' || letter == 'ΐ') {
                return 'ι';
            }
            // upsilon with acute, upsilon with diaeresis, upsilon with acute and diaeresis
            if (letter == 'ύ' || letter == 'ϋ' || letter == 'ΰ') {
                return 'υ';
            }
            // omicron with acute
            if (letter == 'ό') {
                return 'ο';
            }
            // omega with acute
            if (letter == 'ώ') {
                return 'ω';
            }
            // After that, deal with upper case, not accented letters
            if (letter >= 'Α' && letter <= 'Ω') {
                return (char) (letter + 32);
            }
            // Finally deal with upper case, accented letters
            // alpha with acute
            if (letter == 'Ά') {
                return 'α';
            }
            // epsilon with acute
            if (letter == 'Έ') {
                return 'ε';
            }
            // eta with acute
            if (letter == 'Ή') {
                return 'η';
            }
            // iota with acute, iota with diaeresis
            if (letter == 'Ί' || letter == 'Ϊ') {
                return 'ι';
            }
            // upsilon with acute, upsilon with diaeresis
            if (letter == 'Ύ' || letter == 'Ϋ') {
                return 'υ';
            }
            // omicron with acute
            if (letter == 'Ό') {
                return 'ο';
            }
            // omega with acute
            if (letter == 'Ώ') {
                return 'ω';
            }
            return Character.toLowerCase(letter);
        }
