            if (optional == 0 && !rest) {
                int args = paramsLength;
                if (args == 0) {
                    actualRequired = 0;
                } else {
                    if (isStatic) {
                        args--;
                    }
                    if (hasContext) {
                        args--;
                    }
                    if (hasBlock) {
                        // TODO: confirm expected args are IRubyObject (or similar)
                        args--;
                    }
                    actualRequired = args;
                }
            } else {
                // optional args, so we have IRubyObject[]
                // TODO: confirm
                int args = paramsLength;
                if (args == 0) {
                    actualRequired = 0;
                } else {
                    if (isStatic) {
                        args--;
                    }
                    if (hasContext) {
                        args--;
                    }
                    if (hasBlock) {
                        // minus one more for IRubyObject[]
                        args--;
                    }
                    args--;
                    // TODO: confirm expected args are IRubyObject (or similar)
                    actualRequired = args;
                }
                if (actualRequired != 0) {
