public class GetHamburglarLight {
    public static final int getHamburglarLight(final int ronaldPhase, final int grimacePhase, final int hamburglarPosition) {
            //         6    5    4    3
            //
            //       /---\          /---\
            //   7   | R |          | G |   2
            //       \___/          \___/
            //
            //       8   9    10    0   1
            switch(hamburglarPosition) {
                case 0:
                    if (grimacePhase > 0 && grimacePhase < 5) {
                        return -1;
                    }
                    return 1;
                case 1:
                    if (grimacePhase < 4) {
                        return 1;
                    }
                    return -1;
                case 2:
                    if (grimacePhase > 3) {
                        return 1;
                    }
                    return 0;
                case 4:
                    if (grimacePhase > 0 && grimacePhase < 5) {
                        return 1;
                    }
                    return 0;
                case 5:
                    if (ronaldPhase > 3) {
                        return 1;
                    }
                    return 0;
                case 7:
                    if (ronaldPhase > 0 && ronaldPhase < 5) {
                        return 1;
                    }
                    return 0;
                case 8:
                    if (ronaldPhase > 0 && ronaldPhase < 5) {
                        return -1;
                    }
                    return 1;
                case 9:
                    if (ronaldPhase < 4) {
                        return 1;
                    }
                    return -1;
                case 10:
                    int totalEffect = 0;
                    if (ronaldPhase > 3) {
                        ++totalEffect;
                    }
                    if (grimacePhase > 0 && grimacePhase < 5) {
                        ++totalEffect;
                    }
                    return totalEffect;
                default:
                    return 0;
            }
        }
