public class DirChar {
    public static char dirChar(int down, int same, int up) {
            char ch;
            if (down == 0 || same == 0 || up == 0) {
                if (down > 0) {
                    if (up > 0) {
                        if (down > up) {
                            return 'v';
                        }
                        return '^';
                    }
                    if (same > 0) {
                        return '~';
                    }
                    return '\\';
                } else if (up > 0) {
                    if (same > 0) {
                        return '~';
                    }
                    return '/';
                } else {
                    return '_';
                }
            }
            if (down > same) {
                if (down > (same + up)) {
                    return '\\';
                }
                if (up > (down + same)) {
                    return '/';
                }
                if (up > same) {
                    return '^';
                }
            }
            if (up > same) {
                if (up > (down + same)) {
                    return '/';
                }
                if (down > (same + up)) {
                    return '\\';
                }
            }
            if (same > (down + up)) {
                return '-';
            }
            return '~';
        }
