public class GetFlatMushroomCapData {
    public static short getFlatMushroomCapData(int x, int y, int z, int xx, int yy, int zz, int height, int capSize) {
            if (Math.abs(x - xx) < capSize && Math.abs(z - zz) < capSize) {
                // interior blocks
                if (yy < y + height) {
                    // bottom
                    return 0;
                } else {
                    // top
                    return 5;
                }
            } else if (x - xx == capSize) {
                // exterior west blocks
                if (z - zz == capSize - 1) {
                    // west & north
                    return 1;
                } else if (z - zz == -capSize + 1) {
                    // west & south
                    return 7;
                } else {
                    // west only
                    return 4;
                }
            } else if (x - xx == -capSize) {
                // exterior east blocks
                if (z - zz == capSize - 1) {
                    // east & north
                    return 3;
                } else if (z - zz == -capSize + 1) {
                    // east & south
                    return 9;
                } else {
                    // east only
                    return 6;
                }
            } else if (z - zz == capSize) {
                // exterior north
                if (x - xx == capSize - 1) {
                    // west & north
                    return 1;
                } else if (x - xx == -capSize + 1) {
                    // east & north
                    return 3;
                } else {
                    // north only
                    return 2;
                }
            } else if (z - zz == -capSize) {
                // exterior south
                if (x - xx == capSize - 1) {
                    // west & south
                    return 7;
                } else if (x - xx == -capSize + 1) {
                    // east & south
                    return 9;
                } else {
                    // north only
                    return 8;
                }
            } else {
                // unknown location
                return 0;
            }
        }
