                return '`';
            } else if (type == Character.FINAL_QUOTE_PUNCTUATION || c == '\'') {
                return '\'';
            } else if (c == '%') {
                return '%';
            } else if (type == Character.OTHER_PUNCTUATION) {
                return '.';
            } else if (type == Character.CONNECTOR_PUNCTUATION) {
